sys_script_include.script:
var AN_UpdateSetScanner = Class.create();

AN_UpdateSetScanner.prototype = {

    scan: function(scanId) {

        var score = 100;
        var issueCount = 0;

        var usGR = new GlideRecord('sys_update_set');

        usGR.addActiveQuery();
        usGR.orderByDesc('sys_updated_on');
        usGR.query();

        if (usGR.next()) {

            var updateSetName = usGR.getValue('name');

            if (
                updateSetName.toLowerCase() == 'default' ||
                updateSetName.indexOf('Default') > -1
            ) {

                this.createFinding(
                    scanId,
                    'update_set',
                    'high',
                    'Default Update Set in use',
                    'Application changes are being tracked in the Default Update Set.'
                );

                issueCount++;
            }

            var recordCount = parseInt(
                usGR.getValue('customer_updates') || 0,
                10
            );

            if (recordCount === 0) {

                this.createFinding(
                    scanId,
                    'update_set',
                    'medium',
                    'Empty Update Set',
                    'No customer updates found in update set.'
                );

                issueCount++;
            }
        } else {

            this.createFinding(
                scanId,
                'update_set',
                'critical',
                'No Update Set Found',
                'No active update set was found.'
            );

            issueCount += 2;
        }

        score = 100 - (issueCount * 20);

        if (score < 0)
            score = 0;

        var scorecard = new GlideRecord(
            'x_1920012_apprai_0_an_scorecard'
        );

        scorecard.addQuery('scan', scanId);
        scorecard.query();

        if (scorecard.next()) {

            scorecard.update_set_score = score;
            scorecard.update();
        }

        gs.info(
            'Update Set Scanner Complete. Issues=' +
            issueCount
        );
    },

    createFinding: function(
        scanId,
        dimension,
        severity,
        title,
        description
    ) {

        var finding = new GlideRecord(
            'x_1920012_apprai_0_an_finding'
        );

        finding.initialize();

        finding.scan = scanId;
        finding.dimension = dimension;
        finding.severity = severity;
        finding.title = title;
        finding.description = description;

        finding.insert();
    },

    type: 'AN_UpdateSetScanner'
};
